// noteInstrumentFor returns the instrument index for a block state id;
// 0 (harp, the vanilla default) on a lookup miss.
func noteInstrumentFor(state uint32) uint8 {
	lo, hi := 0, len(noteInstrumentRanges)-1
	for lo <= hi {
		mid := int(uint(lo+hi) >> 1)
		r := noteInstrumentRanges[mid]
		switch {
		case state < r.base:
			hi = mid - 1
		case state >= r.base+r.count:
			lo = mid + 1
		default:
			return r.instr
		}
	}
	return 0
}
